  values
    ('era_nt_public_ministry', '제자 부르심: 그물을 버리다', '예수님은 어부들을 부르시고 그들은 삶의 방향을 바꾼다.', '["호숫가, 그물을 손질하는 어부들, 예수가 다가온다", "베드로가 멈칫한다", "배가 뒤로 밀리며 그물이 가득하다", "그들이 그물을 내려놓고 예수를 따라 길을 걷는다"]'::jsonb, '[["jesus"], ["peter"], [], ["jesus"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james', 'john']::text[], '[{"book": "막", "from": "1:16", "to": "1:20"}, {"book": "마", "from": "4:18", "to": "4:22"}, {"book": "눅", "from": "5:1", "to": "5:11"}, {"book": "요", "from": "1:35", "to": "1:51"}]'::jsonb, 27, 27, 'approx', 8, 'lm_nt_pm_sea_of_galilee', 'published'),
